Code:
public int countCode(String str) {
    int count = 0;
    String pattern = "co[a-z]e";
    Pattern r = Pattern.compile(pattern);
    Matcher m = r.matcher(str);
    while (m.find()) {
        count++;
    }
    return count;
}

